class Pong extends Schema.TaggedClass<Pong>()("Pong", { seq: Schema.Number }) {}
const Event = Schema.Union(Ping, Pong)

describe("HttpApiSSE", () => {
  describe("formatMessage", () => {
    it("data only", () => {
      assert.strictEqual(HttpApiSSE.formatMessage({ data: "hello" }), "data: hello\n\n")
    })

    it("multi-line data", () => {
      assert.strictEqual(HttpApiSSE.formatMessage({ data: "a\nb" }), "data: a\ndata: b\n\n")
    })

    it("all fields", () => {
      assert.strictEqual(
        HttpApiSSE.formatMessage({ data: "x", event: "e", id: "1", retry: 500 }),
        "event: e\nid: 1\nretry: 500\ndata: x\n\n"
      )
    })
