      )
    }))

  it.effect("makeUnionEventEncoder falls back to data-only for non-unions", () =>
    Effect.gen(function*() {
      const encode = HttpApiSSE.makeUnionEventEncoder(Schema.Struct({ a: Schema.Number }))
